/* Suggested markup: <div class="uiwiki-sliding-proof-action" tabindex="0"><span>Sliding Proof Action</span></div> */
.uiwiki-sliding-proof-action {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-sliding-proof-action > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #d8f34e;
  animation: sliding_proof_action 1.8s ease-in-out infinite alternate;
}
.uiwiki-sliding-proof-action:hover,
.uiwiki-sliding-proof-action:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes sliding_proof_action {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-sliding-proof-action, .uiwiki-sliding-proof-action > span { animation: none; transition: none; }
}
